<script>
  let count = 0;
  let name = 'World';

  // Reactive declaration — recalculates when count changes
  $: doubled = count * 2;
  $: quadrupled = doubled * 2;
  $: message = `Hello, ${name}! Count is ${count}`;

  // Reactive statement block
  $: if (count > 10) {
    console.log('Count is getting high!');
  }

  // Array reactivity — must reassign, not mutate
  let items = ['apple', 'banana'];
  function addItem(item) {
    items = [...items, item]; // triggers update
    // items.push(item); // does NOT trigger update!
  }
  function removeItem(index) {
    items = items.filter((_, i) => i !== index);
  }

  // Object reactivity
  let user = { name: 'Alice', age: 30 };
  function birthday() {
    user = { ...user, age: user.age + 1 }; // must reassign
  }
</script>

<h1>{message}</h1>
<p>Count: {count}, Doubled: {doubled}, Quadrupled: {quadrupled}</p>
<button on:click={() => count++}>Increment</button>
<input bind:value={name}>

<ul>
  {#each items as item, i}
    <li>{item} <button on:click={() => removeItem(i)}>x</button></li>
  {/each}
</ul>
<input on:keydown={(e) => e.key === 'Enter' && addItem(e.target.value)}>

<p>{user.name} is {user.age} years old</p>
<button on:click={birthday}>Birthday!</button>
