// stores/counter.ts
import { writable, derived, readable } from 'svelte/store';

// Writable — read and write
export const count = writable(0);
export const increment = () => count.update(n => n + 1);
export const decrement = () => count.update(n => n - 1);
export const reset = () => count.set(0);

// Derived — computed from other stores
export const doubled = derived(count, $count => $count * 2);
export const isEven = derived(count, $count => $count % 2 === 0);

// Readable — read-only (e.g., timer)
export const time = readable(new Date(), function start(set) {
  const interval = setInterval(() => set(new Date()), 1000);
  return function stop() { clearInterval(interval); };
});

// Custom store with persistence
function createTodoStore() {
  const stored = typeof localStorage !== 'undefined'
    ? JSON.parse(localStorage.getItem('todos') || '[]') : [];
  const { subscribe, set, update } = writable(stored);

  return {
    subscribe,
    add: (text) => update(todos => {
      const updated = [...todos, { id: Date.now(), text, done: false }];
      localStorage.setItem('todos', JSON.stringify(updated));
      return updated;
    }),
    toggle: (id) => update(todos => {
      const updated = todos.map(t => t.id === id ? { ...t, done: !t.done } : t);
      localStorage.setItem('todos', JSON.stringify(updated));
      return updated;
    }),
    remove: (id) => update(todos => {
      const updated = todos.filter(t => t.id !== id);
      localStorage.setItem('todos', JSON.stringify(updated));
      return updated;
    }),
    clear: () => { set([]); localStorage.removeItem('todos'); }
  };
}
export const todos = createTodoStore();
