<script>
  import { onMount, onDestroy, beforeUpdate, afterUpdate, tick } from 'svelte';

  let data = [];
  let loading = true;
  let error = null;
  let scrollY = 0;
  let listEl;

  // Runs once after first render
  onMount(async () => {
    try {
      const res = await fetch('/api/posts');
      data = await res.json();
    } catch (e) {
      error = e.message;
    } finally {
      loading = false;
    }

    // Return a cleanup function (called on destroy)
    const handler = () => { scrollY = window.scrollY; };
    window.addEventListener('scroll', handler);
    return () => window.removeEventListener('scroll', handler);
  });

  // Timer with cleanup
  let seconds = 0;
  let interval;
  onMount(() => {
    interval = setInterval(() => seconds++, 1000);
    return () => clearInterval(interval);
  });

  // Scroll to bottom after new messages
  let messages = [];
  afterUpdate(() => {
    if (listEl) {
      listEl.scrollTop = listEl.scrollHeight;
    }
  });

  async function addMessage(text) {
    messages = [...messages, { text, time: new Date() }];
    await tick(); // wait for DOM update
    console.log('List height:', listEl.scrollHeight);
  }

  // AbortController for fetch cancellation
  let controller;
  onMount(() => {
    controller = new AbortController();
    fetch('/api/events', { signal: controller.signal })
      .then(res => res.json())
      .then(d => { data = d; })
      .catch(e => { if (e.name !== 'AbortError') error = e.message; });
    return () => controller.abort();
  });
</script>

{#if loading}
  <p>Loading...</p>
{:else if error}
  <p class="error">{error}</p>
{:else}
  <ul bind:this={listEl}>
    {#each data as item}
      <li>{item.title}</li>
    {/each}
  </ul>
{/if}

<p>Uptime: {seconds}s | Scroll: {scrollY}px</p>
