        return updated;
      }),
      toggle: (id) => update(todos => {
        const updated = todos.map(t => t.id === id ? {...t, done: !t.done} : t);
        localStorage.setItem('todos', JSON.stringify(updated));
        return updated;
      }),
      remove: (id) => update(todos => {
        const updated = todos.filter(t => t.id !== id);
