<!-- Reactive Todo List with Store -->
<script>
  import { writable, derived } from 'svelte/store';
  import { fly, fade } from 'svelte/transition';

  const todos = writable([]);
  const activeCount = derived(todos, $t => $t.filter(t => !t.done).length);
  let text = '';

  function add() {
    if (!text.trim()) return;
    todos.update(t => [...t, { id: Date.now(), text, done: false }]);
    text = '';
  }

  function toggle(id) {
    todos.update(t => t.map(item =>
      item.id === id ? { ...item, done: !item.done } : item
    ));
  }

  function remove(id) {
    todos.update(t => t.filter(item => item.id !== id));
  }
</script>

<form on:submit|preventDefault={add}>
  <input bind:value={text} placeholder="Add todo..." />
  <button>Add</button>
</form>

<p>{$activeCount} remaining</p>
{#each $todos as todo (todo.id)}
  <div transition:fly={{ y: 20 }}>
    <input type="checkbox" checked={todo.done} on:change={() => toggle(todo.id)} />
    <span class:done={todo.done}>{todo.text}</span>
    <button on:click={() => remove(todo.id)}>x</button>
  </div>
{/each}

<style>
  .done { text-decoration: line-through; opacity: 0.5; }
</style>
